def main():
    with open('data/task_14_spelling.json', encoding='utf-8') as f:
        data = json.load(f)

    questions = data['subcategories'][0]['questions']
    assert len(questions) == 279, f"Expected 279 questions, got {len(questions)}"
    assert len(EXPLANATION_BY_INDEX) == 279, f"Expected 279 explanations, got {len(EXPLANATION_BY_INDEX)}"

    for i, q in enumerate(questions):
        q['explanation'] = EXPLANATION_BY_INDEX[i]

    # Verify all explanations are > 50 chars
    short = [(i, q['word_display'], len(q['explanation']), q['explanation'])
             for i, q in enumerate(questions) if len(q['explanation']) <= 50]
    if short:
        print(f"WARNING: {len(short)} explanations are still <= 50 chars:")
        for i, w, l, e in short:
            print(f"  [{i}][{l}] {w}: {e}")
        return

    with open('data/task_14_spelling.json', 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)

    print(f"Done! Updated {len(questions)} questions. All explanations > 50 chars.")


if __name__ == '__main__':
    main()
